def _resolve_wwwroot_path() -> Path:
    """Resolve the shared runtime data root.

    Keep this aligned with the local-dev behavior used by the retriever and admin
    tooling so Windows localhost runs do not accidentally read stale overrides
    from ``C:\\home\\data\\lumae``.
    """

    raw = (
        os.environ.get("LUMAE_WWWROOT_PATH")
        or os.environ.get("LUMAE_DATA_DIR")
        or os.environ.get("WWWROOT_PATH")
    )
    if isinstance(raw, str) and raw.strip():
        return Path(raw.strip()).expanduser()

    if os.name == "nt":
        return PROJECT_ROOT

    return Path("/home/data/lumae")


