function resolvePdfPasswordCacheKey(resource) {
    if (!resource) return '';
    if (typeof resource === 'string') return resource;
    const explicit = resource.passwordKey || resource.cacheKey;
    if (explicit) return String(explicit);
    const analysisId = resource.analysisId || resource.fileId || resource.id;
    if (analysisId) return `analysis:${analysisId}`;
    const fetchUrl = resource.fetchUrl || '';
    const analysisMatch = fetchUrl.match(/\/api\/fileanalysis\/file\/([^/]+)\/content/i);
    if (analysisMatch) {
        return `analysis:${decodeURIComponent(analysisMatch[1])}`;
    }
    const path = resource.path || '';
    if (path) return `path:${path}`;
    if (fetchUrl) return `url:${fetchUrl}`;
    return '';
}

function storeDocumentViewerPassword(resourceOrKey, password) {
    if (!password) return;
    const key = resolvePdfPasswordCacheKey(resourceOrKey);
    if (key) {
        pdfPasswordCache.set(key, password);
    }
}

function resolveDocumentViewerPassword(resourceOrKey) {
    const key = resolvePdfPasswordCacheKey(resourceOrKey);
    if (!key) return null;
    return pdfPasswordCache.get(key) || null;
}

